"/* ==========================================================================
   TrustShield AI Design System & Core Styles
   Theme: Modern Dark Mode, Glassmorphism, Neon Highlights, Premium Micro-Interactions
   ========================================================================== */

:root {
    --bg-base: #06040c;
    --bg-surface: rgba(16, 12, 30, 0.75);
    --bg-surface-solid: #110c22;
    --bg-surface-light: rgba(28, 22, 48, 0.6);
    --border-color: rgba(138, 43, 226, 0.15);
    --border-color-hover: rgba(138, 43, 226, 0.35);

    --text-primary: #f1f0f6;
    --text-secondary: #a3a1b8;
    --text-muted: #6e6b85;

    --color-purple: #8a2be2;
    --color-purple-glow: rgba(138, 43, 226, 0.4);
    --color-teal: #00f5ff;
    --color-teal-glow: rgba(0, 245, 255, 0.4);

    /* Risk Spectrum Colors */
    --color-safe: #10b981;
    --color-suspicious: #3b82f6;
    --color-high-risk: #f59e0b;
    --color-critical: #ef4444;

    --font-sans: 'Outfit', sans-serif;
    --font-mono: 'Space Grotesk', sans-serif;

    --transition-smooth: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
    --blur-intensity: 16px;
}

* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

html {
    scroll-behavior: smooth;
}

body {
    background-color: var(--bg-base);
    background-image: 
